UPDATE TB_WB20M03
   SET TODO_CF_DT = SYSDATE,
       TODO_CF_OPN = #{todoCfOpn},
       UDT_ID = #{todoId},
       UDT_PGM = #{creatPgm},
       UDT_DTTM = SYSDATE
 WHERE
       TODO_FILE_TRGT_KEY = #{todoFileTrgtKey}
       AND TODO_DIV1_CODE_ID = #{todoDiv1CodeId}
       AND TODO_DIV2_CODE_ID = #{todoDiv2CodeId}
       AND SALES_CD = #{salesCd}
       AND SANCTN_SN = #{sanctnSn}

mapper.select:
SELECT A.TODO_KEY , A.SANCTN_SN , A.CO_CD , A.TODO_DIV1_CODE_ID , A.TODO_DIV2_CODE_ID , A.TODO_ID /* 대상자 ID */ , B.NAME AS TODO_NM /* 작성자 이름 */ /* 결재요청자와 결재자가 같은 팀이면 팀장구분을 리턴하고 그외는 공백으로 처리함(이슈 결재처리시 위험도평가에서 사용함 */ , CASE WHEN (A.TODO_DIV2_CODE_ID = 'TODODIV2090' AND C.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' WHEN (A.TODO_DIV2_CODE_ID = 'TODODIV2020' AND QP.SAME_TIME_RESULT = 'Y' AND D.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' WHEN (A.TODO_DIV2_CODE_ID = 'TODODIV2030' AND D.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' ELSE '' END AS TEAM_MANAGER --작성자 담당팀장인경우에 평가 , NVL(TO_CHAR(A.TODO_CF_DT, 'YYYY-MM-DD'), ' ') AS TODO_CF_DT /* 승인일자 */ , A.TODO_CF_OPN , A.SANCTN_STTUS , DECODE(A.SANCTN_STTUS, 'Y', '승인', 'N', '미승인', ' ') AS SANCTN_STTUS_NM , B.TEAM_MANAGER AS DEPT_TEAM_MANAGER , ( SELECT SANCTN_STTUS FROM ( SELECT SANCTN_STTUS , ROWNUM RN FROM TB_WB20M03 B WHERE 1=1 AND A.SANCTN_SN > B.SANCTN_SN AND A.CO_CD = B.CO_CD AND A.TODO_DIV1_CODE_ID = B.TODO_DIV1_CODE_ID AND A.TODO_DIV2_CODE_ID = B.TODO_DIV2_CODE_ID
AND A.TODO_NO = B.TODO_NO ORDER BY B.SANCTN_SN DESC ) WHERE RN=1 ) AS PRE_STTUS /* 하위 완료여부 */ , ( SELECT SANCTN_STTUS FROM ( SELECT SANCTN_STTUS , ROWNUM RN FROM TB_WB20M03 B WHERE 1=1 AND A.SANCTN_SN < B.SANCTN_SN AND A.CO_CD = B.CO_CD AND A.TODO_DIV1_CODE_ID = B.TODO_DIV1_CODE_ID AND A.TODO_DIV2_CODE_ID = B.TODO_DIV2_CODE_ID
AND A.TODO_NO = B.TODO_NO ORDER BY B.SANCTN_SN DESC ) WHERE RN=1 ) AS NEXT_STTUS /* 상위 완료여부 */ , A.SALES_CD , A.PG_PATH , SUBSTR(A.PG_PATH, INSTR(A.PG_PATH, '/', -1)+1) AS DOC_NM /* 문서명 pgmId */ , A.TODO_FILE_TRGT_KEY , A.TODO_CO_CD , A.TODO_NO , A.TODO_CODE_KIND , A.TODO_CODE_ID , NVL(NVL(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), TO_CHAR(A.CREAT_DTTM, 'YYYY-MM-DD')), ' ') AS CREAT_DTTM , A.PG_PARAM , SUBSTR(B.DEPT_ID, 1, 5) AS DEPT_ID , A.ETC_FIELD1 AS ACT_MH , QM.PART_CD , NVL(QP.SAME_TIME_RESULT, 'N') AS SAME_TIME_RESULT FROM TB_WB20M03 A LEFT OUTER JOIN TB_CM06M01 B ON A.TODO_ID = B.ID LEFT OUTER JOIN TB_CM06M01 C ON A.CREAT_ID = C.ID LEFT OUTER JOIN TB_QM01P01 QP ON A.TODO_NO = QP.REQ_NO OR A.TODO_NO = QP.RSLT_NO LEFT OUTER JOIN TB_QM01M01 QM ON QP.REQ_NO = QM.REQ_NO LEFT OUTER JOIN TB_CM06M01 D ON QM.ORDRG_ID = D.ID WHERE 1=1
AND A.TODO_KEY = #{todoKey}
AND A.SANCTN_SN = #{sanctnSn}
AND A.CO_CD = #{coCd}
AND A.TODO_DIV1_CODE_ID = #{todoDiv1CodeId}
AND A.TODO_DIV2_CODE_ID = #{todoDiv2CodeId}
AND A.SALES_CD = #{salesCd}
AND A.PG_PATH = #{pgPath}
AND A.TODO_FILE_TRGT_KEY = #{todoFileTrgtKey}
AND A.TODO_CO_CD = #{todoCoCd}
AND A.TODO_NO = #{todoNo}
AND A.ETC_FIELD2 = #{histNo}
AND A.CREAT_DTTM IN ( SELECT MAX(CREAT_DTTM) FROM TB_WB20M03 WHERE 1 = 1
AND TODO_KEY = #{todoKey}
AND TODO_CO_CD = #{todoCoCd}
AND TODO_DIV1_CODE_ID = #{todoDiv1CodeId}
AND TODO_DIV2_CODE_ID = #{todoDiv2CodeId}
AND SALES_CD = #{salesCd}
AND TODO_FILE_TRGT_KEY = #{todoFileTrgtKey}
AND TODO_NO = #{todoNo}
AND ETC_FIELD2 = #{histNo}
) ORDER BY A.SANCTN_SN DESC

