UPDATE TB_WB20M03
   SET
		  TODO_CF_DT = SYSDATE
		, SANCTN_STTUS = 'Y'
		, TODO_CF_OPN = #{todoCfOpn}
		, UDT_ID = #{userId}
		, UDT_PGM = #{pgmId}
		, UDT_DTTM = SYSDATE
		, ETC_FIELD1 = #{etcField1, jdbcType=VARCHAR} --팀장 작업공수 입력용으로 활용 2025.07.22
WHERE TODO_KEY = #{todoKey}
  AND SANCTN_SN = #{sanctnSn}
  AND TODO_DIV1_CODE_ID = #{todoDiv1CodeId}
  AND TODO_DIV2_CODE_ID = #{todoDiv2CodeId}

mapper.select:
SELECT * FROM( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT A.CO_CD AS WBS_PLANCO_CD, A.CO_CD, FN_CM05M01_CD_TO_NM(A.CO_CD) WBS_PLANCO_CD_NM, A.ID AS USR_NM, A.EMP_NO AS EMP_NO, A.NAME AS NAME, A.TEL_NO AS TEL_NO, A.EMAIL AS EMAIL, A.DEPT_ID, B.DEPT_NM AS DT_NM, D.LEVEL_NM AS JIK, C.TODO_DIV1_CODE_ID AS TODO_DIV1_CODE_ID, DECODE(C.TODO_DIV1_CODE_ID, 'TODODIV10', '공유', 'TODODIV20', '결재', '') AS GB , C.SANCTN_STTUS , DECODE(C.SANCTN_STTUS, 'Y', '승인', 'N', '미승인', ' ') AS SANCTN_STTUS_NM , NVL(TO_CHAR(C.CREAT_DTTM, 'YYYY-MM-DD'), '') AS CREAT_DTTM /* 요청일자 */ , NVL(TO_CHAR(C.TODO_CF_DT, 'YYYY-MM-DD'), '') AS TODO_CF_DT /* 승인일자 */ , C.TODO_CF_OPN /* 확인의견 */ , C.TODO_KEY , C.SANCTN_SN , C.TODO_ID , C.TODO_DIV1_CODE_ID , C.TODO_DIV2_CODE_ID , C.SALES_CD , 'U' AS FLAG , C.ETC_FIELD1 , DECODE(A.TEAM_MANAGER, 'TEAM01', 'Y', 'N') AS TEAM_MANAGER -- 팀장여부 FROM TB_CM06M01 A LEFT OUTER JOIN TB_CM07M01 D ON A.LEVEL_CD = D.LEVEL_CD INNER JOIN TB_CM04M01 B on A.DEPT_ID = B.DEPT_ID INNER JOIN TB_WB20M03 C ON A.ID = C.TODO_ID AND C.TODO_FILE_TRGT_KEY = #{fileTrgtKey} AND C.TODO_NO = #{reqNo}
AND C.ETC_FIELD2 = #{etcField2}
ORDER BY C.TODO_DIV1_CODE_ID DESC, SANCTN_SN ASC, CREAT_DTTM ASC ) AS a ) A

