UPDATE TB_WB20M03 A
	SET SANCTN_SN = (
					SELECT RN
		              FROM
		              (
		              	SELECT RID, ROWNUM RN
		                  FROM
		                  (
	                  		SELECT ROWID RID
	                          FROM TB_WB20M03
	                         WHERE TODO_NO = #{todoNo}
	                           AND TODO_DIV2_CODE_ID = #{todoDiv2CodeId}
	                         ORDER BY SANCTN_SN
                          )
	                  )
		            WHERE RID = A.ROWID
	            	)
WHERE A.TODO_NO = #{todoNo}
  AND A.TODO_DIV2_CODE_ID = #{todoDiv2CodeId}

mapper.select:
SELECT Z.* FROM ( SELECT X.* , ROWNUM AS RN FROM ( SELECT T.CO_CD , T.TODO_KEY --TO DO KEY , T.TODO_DIV1_CODE_ID --TO DO 구분(공유-결재) , T.TODO_DIV2_CODE_ID , FN_CM05M01_CD_TO_NM(T.TODO_DIV1_CODE_ID) AS TODO_DIV1_CODE_NM --TO DO 구분(공유-결재) 명 , X.CODE_NM AS TODO_DIV2_CODE_NM --발생프로그램 명 , T.SALES_CD --Sales Code , T.TODO_NO --관리번호 , T.SANCTN_SN --결제순번 , T.TODO_ID , B.NAME AS TODO_NM --대상자명 /* 결재요청자와 결재자가 같은 팀이면 팀장구분을 리턴하고 그외는 공백으로 처리함(이슈 결재처리시 위험도평가에서 사용함 * 계획이슈 조치결과, 실적이슈 조치결과는 팀장이 위험도 평가를 해야함 */ , CASE WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2090' AND C.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2020' AND QP.SAME_TIME_RESULT = 'Y' AND D.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2030' AND D.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' ELSE '' END AS TEAM_MANAGER --작성자 담당팀장인경우에 평가 , T.SANCTN_STTUS , T.PG_PATH , T.TODO_FILE_TRGT_KEY , T.TODO_NO , CASE WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2100' OR T.TODO_DIV2_CODE_ID = 'TODODIV1100') THEN (T.TODO_NO ||' ' || T.ETC_FIELD2 || '차') ELSE T.TODO_NO END AS SHW_TODO_NO , T.PG_PARAM , TO_CHAR(T.TODO_CF_DT, 'YYYY-MM-DD') AS TODO_CF_DT --확인일자 , T.TODO_CF_OPN --확인의견 , T.CREAT_ID --생성자 , C.NAME AS CREAT_NM /*생성자명 */ , TO_CHAR(T.CREAT_DTTM, 'YYYY-MM-DD') AS CREAT_DTTM --생성일시 , T.UDT_ID --최종변경자 , ( SELECT A.NAME FROM TB_CM06M01 AS A WHERE A.ID = T.UDT_ID ) AS UDT_NM /*변경자명 */ , TO_CHAR(T.UDT_DTTM, 'YYYY-MM-DD') AS UDT_DTTM --최종변경일자 , T.TODO_TITL AS TODO_TITL , T.CREAT_PGM , T.ETC_FIELD2 , NVL(( SELECT COUNT(*) CNT FROM TB_WB20M03 S WHERE S.TODO_DIV1_CODE_ID = T.TODO_DIV1_CODE_ID AND S.TODO_DIV2_CODE_ID = T.TODO_DIV2_CODE_ID AND S.SALES_CD = T.SALES_CD AND S.TODO_NO = T.TODO_NO AND S.SANCTN_STTUS = 'N' AND S.TODO_ID != T.TODO_ID AND S.SANCTN_SN < T.SANCTN_SN ), 0) AS BEFORE_NOT_CONFIRM --이전미결자료 존재여부 FROM TB_WB20M03 T LEFT OUTER JOIN TB_CM05M01 X ON X.CODE_ID = T.TODO_DIV2_CODE_ID LEFT OUTER JOIN TB_CM06M01 B ON T.TODO_ID = B.ID LEFT OUTER JOIN TB_CM06M01 C ON T.CREAT_ID = C.ID LEFT OUTER JOIN TB_QM01P01 QP ON T.TODO_NO = QP.REQ_NO OR T.TODO_NO = QP.RSLT_NO LEFT OUTER JOIN TB_QM01M01 QM ON QP.REQ_NO = QM.REQ_NO LEFT OUTER JOIN TB_CM06M01 D ON QM.ORDRG_ID = D.ID WHERE 1 = 1
/* ORDER BY T.SALES_CD DESC, T.TODO_NO DESC, T.SANCTN_SN DESC */ ORDER BY TODO_DIV1_CODE_NM, TODO_DIV2_CODE_NM, SALES_CD DESC, TODO_NM ) AS X WHERE 1=1
AND BEFORE_NOT_CONFIRM = 0 --이전 미결자료 존재 여부 (전무님만 해당되게 변경 처리함 2025.03.06)
) AS Z WHERE 1 = 1 AND Z.RN BETWEEN ${firstIndex} AND ${lastIndex}

SELECT T.CO_CD , T.TODO_KEY --TO DO KEY , T.TODO_DIV1_CODE_ID --TO DO 구분(공유-결재) , T.TODO_DIV2_CODE_ID , FN_CM05M01_CD_TO_NM(T.TODO_DIV1_CODE_ID) AS TODO_DIV1_CODE_NM --TO DO 구분(공유-결재) 명 , X.CODE_NM AS TODO_DIV2_CODE_NM --발생프로그램 명 , T.SALES_CD --Sales Code , T.TODO_NO --관리번호 , T.SANCTN_SN --결제순번 , T.TODO_ID , B.NAME AS TODO_NM --대상자명 /* 결재요청자와 결재자가 같은 팀이면 팀장구분을 리턴하고 그외는 공백으로 처리함(이슈 결재처리시 위험도평가에서 사용함 * 계획이슈 조치결과, 실적이슈 조치결과는 팀장이 위험도 평가를 해야함 */ , CASE WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2090' AND C.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2020' AND QP.SAME_TIME_RESULT = 'Y' AND D.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2030' AND D.MNG_ID = B.ID AND B.TEAM_MANAGER = 'TEAM01') THEN '평가' ELSE '' END AS TEAM_MANAGER --작성자 담당팀장인경우에 평가 , T.SANCTN_STTUS , T.PG_PATH , T.TODO_FILE_TRGT_KEY , T.TODO_NO , CASE WHEN (T.TODO_DIV2_CODE_ID = 'TODODIV2100' OR T.TODO_DIV2_CODE_ID = 'TODODIV1100') THEN (T.TODO_NO ||' ' || T.ETC_FIELD2 || '차') ELSE T.TODO_NO END AS SHW_TODO_NO , T.PG_PARAM , TO_CHAR(T.TODO_CF_DT, 'YYYY-MM-DD') AS TODO_CF_DT --확인일자 , T.TODO_CF_OPN --확인의견 , T.CREAT_ID --생성자 , C.NAME AS CREAT_NM /*생성자명 */ , TO_CHAR(T.CREAT_DTTM, 'YYYY-MM-DD') AS CREAT_DTTM --생성일시 , T.UDT_ID --최종변경자 , ( SELECT A.NAME FROM TB_CM06M01 AS A WHERE A.ID = T.UDT_ID ) AS UDT_NM /*변경자명 */ , TO_CHAR(T.UDT_DTTM, 'YYYY-MM-DD') AS UDT_DTTM --최종변경일자 , T.TODO_TITL AS TODO_TITL , T.CREAT_PGM , T.ETC_FIELD2 , NVL(( SELECT COUNT(*) CNT FROM TB_WB20M03 S WHERE S.TODO_DIV1_CODE_ID = T.TODO_DIV1_CODE_ID AND S.TODO_DIV2_CODE_ID = T.TODO_DIV2_CODE_ID AND S.SALES_CD = T.SALES_CD AND S.TODO_NO = T.TODO_NO AND S.SANCTN_STTUS = 'N' AND S.TODO_ID != T.TODO_ID AND S.SANCTN_SN < T.SANCTN_SN ), 0) AS BEFORE_NOT_CONFIRM --이전미결자료 존재여부 , DECODE(B.TEAM_MANAGER, 'TEAM01', 'Y', 'N') AS TEAM_MANAGER_CHECK FROM TB_WB20M03 T LEFT OUTER JOIN TB_CM05M01 X ON X.CODE_ID = T.TODO_DIV2_CODE_ID LEFT OUTER JOIN TB_CM06M01 B ON T.TODO_ID = B.ID LEFT OUTER JOIN TB_CM06M01 C ON T.CREAT_ID = C.ID LEFT OUTER JOIN TB_QM01P01 QP ON T.TODO_NO = QP.REQ_NO OR T.TODO_NO = QP.RSLT_NO LEFT OUTER JOIN TB_QM01M01 QM ON QP.REQ_NO = QM.REQ_NO LEFT OUTER JOIN TB_CM06M01 D ON QM.ORDRG_ID = D.ID WHERE 1 = 1 AND T.SANCTN_STTUS = 'N' AND T.TODO_NO = #{todoNo} AND T.TODO_FILE_TRGT_KEY = #{todoFileTrgtKey} AND T.TODO_ID = #{userId}
AND T.SALES_CD = #{salesCd}
AND T.ETC_FIELD2 = #{etcField2}
ORDER BY T.TODO_DIV1_CODE_ID DESC, T.CREAT_DTTM ASC

mapper.update:
MERGE INTO TB_WB20D01
	USING DUAL ON (CO_CD = #{coCd} AND CODE_ID = #{codeId} AND USER_ID = #{userId})
WHEN MATCHED THEN
	UPDATE SET
				  RECEIVE_YN = #{receiveYn}
				, CHK_DTTM = CASE WHEN RECEIVE_YN != #{receiveYn} THEN SYSDATE ELSE CHK_DTTM END
				, CHK_USER_ID = CASE WHEN RECEIVE_YN != #{receiveYn} THEN #{chkUserId} ELSE CHK_USER_ID END
				, CHK_PGM_ID = #{pgmId}
				, REMARK = #{remark, jdbcType=VARCHAR}
		WHEN NOT MATCHED THEN
	INSERT (
				  CO_CD
				, CODE_ID
				, USER_ID
				, RECEIVE_YN
				, CHK_DTTM
				, CHK_USER_ID
				, CHK_PGM_ID
				, REMARK
			)
	VALUES (
				  #{coCd}
				, #{codeId}
				, #{userId}
				, #{receiveYn}
				, CASE WHEN #{receiveYn} = 'N' THEN SYSDATE ELSE NULL END
				, CASE WHEN #{receiveYn} = 'N' THEN #{chkUserId} ELSE NULL END
				, #{pgmId}
				, #{remark, jdbcType=VARCHAR}
			)

mapper.insert:
INSERT INTO TB_WB20M03
(
	  TODO_KEY
	, SANCTN_SN
	, CO_CD
	, TODO_DIV1_CODE_ID
	, TODO_DIV2_CODE_ID
	, TODO_ID
	, SALES_CD
	, PG_PATH
	, TODO_FILE_TRGT_KEY
	, TODO_CO_CD
	, TODO_NO
	, CREAT_ID
	, CREAT_PGM
	, CREAT_DTTM
	, PG_PARAM
	, TODO_TITL
	, ETC_FIELD2
	, ETC_FIELD3
	, TODO_CODE_ID
)
SELECT
	#{toDoKey}
	, #{sanCtnSn}
	, #{coCd}
	, #{todoDiv1CodeId}
	, #{todoDiv2CodeId}
	, #{usrNm}
	, #{salesCd, jdbcType=VARCHAR}
	, #{pgPath}
	, #{fileTrgtKey}
	, #{todoCoCd}
	, #{reqNo}
	, #{userId}
	, #{pgmId}
	, ( SELECT nvl(max(CREAT_DTTM), SYSDATE)
		FROM TB_WB20M03 T
		WHERE T.TODO_FILE_TRGT_KEY = #{fileTrgtKey}
		AND T.TODO_NO            = #{reqNo}
		AND T.CREAT_PGM          = #{pgmId, jdbcType=VARCHAR}

		AND T.ETC_FIELD2       = #{histNo, jdbcType=VARCHAR}

	   )
	, #{pgParam}
	, (SELECT #{todoTitle, jdbcType=VARCHAR}||' '||FN_CR02_KAKAO_TITLE_NM(#{reqNo}, #{histNo, jdbcType=VARCHAR}) FROM DUAL)
	, #{histNo, jdbcType=VARCHAR}
	, 'N'
	, 'insertWbsSharngList'
FROM DUAL
WHERE NOT EXISTS (
	SELECT 1
	FROM TB_WB20M03 X
	WHERE X.TODO_FILE_TRGT_KEY = #{fileTrgtKey}
	AND X.TODO_ID            = #{usrNm}
	AND X.TODO_NO            = #{reqNo}

		AND X.ETC_FIELD2       = #{histNo, jdbcType=VARCHAR}

)
